import React, { useState, useEffect } from 'react';
import { Container, Form, Button, Card, Row, Col, Badge, Spinner } from 'react-bootstrap';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faSearch, faFilter, faClock, faCode, faBuilding, faTags, faBookmark, faStar } from '@fortawesome/free-solid-svg-icons';
import '../styles/AdvancedSearch.css';

const AdvancedSearch = () => {
    const [filters, setFilters] = useState({
        company: '',
        difficulty: '',
        type: '',
        keywords: '',
        timeframe: 'all'
    });

    const [questions, setQuestions] = useState([]);
    const [isLoading, setIsLoading] = useState(false);
    const [selectedTags, setSelectedTags] = useState([]);

    // Sample data - Replace with actual API call
    const sampleQuestions = [
        {
            id: 1,
            title: "Design a Distributed Cache System",
            company: "Google",
            difficulty: "Hard",
            type: "System Design",
            description: "Design a distributed caching system with high availability and eventual consistency...",
            tags: ["system-design", "distributed-systems", "caching"],
            likes: 234,
            bookmarks: 56,
            timePosted: "2 days ago"
        },
        {
            id: 2,
            title: "Implement LRU Cache",
            company: "Microsoft",
            difficulty: "Medium",
            type: "Coding",
            description: "Implement a data structure for Least Recently Used (LRU) cache...",
            tags: ["data-structures", "algorithms", "cache"],
            likes: 189,
            bookmarks: 45,
            timePosted: "1 week ago"
        },
        {
            id: 3,
            title: "Database Indexing Best Practices",
            company: "Amazon",
            difficulty: "Medium",
            type: "Database",
            description: "Explain different types of database indexes and their use cases...",
            tags: ["database", "optimization", "indexing"],
            likes: 156,
            bookmarks: 34,
            timePosted: "3 days ago"
        }
    ];

    const difficulties = ['Easy', 'Medium', 'Hard'];
    const questionTypes = ['Coding', 'Theory', 'Database', 'System Design'];
    const timeframes = [
        { value: 'all', label: 'All Time' },
        { value: 'day', label: 'Last 24 Hours' },
        { value: 'week', label: 'Last Week' },
        { value: 'month', label: 'Last Month' }
    ];

    const popularTags = [
        'algorithms', 'data-structures', 'system-design', 'database',
        'frontend', 'backend', 'distributed-systems', 'machine-learning'
    ];

    useEffect(() => {
        // Simulating initial data load
        setQuestions(sampleQuestions);
    }, []);

    const handleSearch = (e) => {
        e.preventDefault();
        setIsLoading(true);

        // Simulate API call with filters
        setTimeout(() => {
            const filteredQuestions = sampleQuestions.filter(question => {
                const matchesCompany = !filters.company || 
                    question.company.toLowerCase().includes(filters.company.toLowerCase());
                const matchesDifficulty = !filters.difficulty || 
                    question.difficulty === filters.difficulty;
                const matchesType = !filters.type || 
                    question.type === filters.type;
                const matchesKeywords = !filters.keywords ||
                    question.title.toLowerCase().includes(filters.keywords.toLowerCase()) ||
                    question.description.toLowerCase().includes(filters.keywords.toLowerCase());
                const matchesTags = selectedTags.length === 0 ||
                    selectedTags.every(tag => question.tags.includes(tag));

                return matchesCompany && matchesDifficulty && 
                       matchesType && matchesKeywords && matchesTags;
            });

            setQuestions(filteredQuestions);
            setIsLoading(false);
        }, 1000);
    };

    return (
        <Container className="py-4">
            <h2 className="mb-4">Advanced Question Search</h2>
            <Card className="shadow-sm">
                <Card.Body>
                    <Form onSubmit={handleSearch}>
                        <Row>
                            <Col md={6}>
                                <Form.Group className="mb-3">
                                    <Form.Label>Company</Form.Label>
                                    <Form.Control
                                        type="text"
                                        placeholder="Enter company name"
                                        value={filters.company}
                                        onChange={(e) => setFilters({...filters, company: e.target.value})}
                                    />
                                </Form.Group>
                            </Col>
                            <Col md={6}>
                                <Form.Group className="mb-3">
                                    <Form.Label>Difficulty</Form.Label>
                                    <Form.Select
                                        value={filters.difficulty}
                                        onChange={(e) => setFilters({...filters, difficulty: e.target.value})}
                                    >
                                        <option value="">All Difficulties</option>
                                        {difficulties.map(diff => (
                                            <option key={diff} value={diff.toLowerCase()}>
                                                {diff}
                                            </option>
                                        ))}
                                    </Form.Select>
                                </Form.Group>
                            </Col>
                        </Row>

                        <Row>
                            <Col md={6}>
                                <Form.Group className="mb-3">
                                    <Form.Label>Question Type</Form.Label>
                                    <Form.Select
                                        value={filters.type}
                                        onChange={(e) => setFilters({...filters, type: e.target.value})}
                                    >
                                        <option value="">All Types</option>
                                        {questionTypes.map(type => (
                                            <option key={type} value={type.toLowerCase()}>
                                                {type}
                                            </option>
                                        ))}
                                    </Form.Select>
                                </Form.Group>
                            </Col>
                            <Col md={6}>
                                <Form.Group className="mb-3">
                                    <Form.Label>Time Frame</Form.Label>
                                    <Form.Select
                                        value={filters.timeframe}
                                        onChange={(e) => setFilters({...filters, timeframe: e.target.value})}
                                    >
                                        {timeframes.map(({ value, label }) => (
                                            <option key={value} value={value}>
                                                {label}
                                            </option>
                                        ))}
                                    </Form.Select>
                                </Form.Group>
                            </Col>
                        </Row>

                        <Form.Group className="mb-3">
                            <Form.Label>Keywords</Form.Label>
                            <Form.Control
                                type="text"
                                placeholder="Enter keywords (comma separated)"
                                value={filters.keywords}
                                onChange={(e) => setFilters({...filters, keywords: e.target.value})}
                            />
                        </Form.Group>

                        <Button variant="primary" type="submit" className="w-100">
                            Search Questions
                        </Button>
                    </Form>
                </Card.Body>
            </Card>
        </Container>
    );
};

export default AdvancedSearch;
